from flask import Flask, request
import json
from typing import Dict

app = Flask(__name__)


@app.route("/api", methods=["GET"])
def api_endpoint():
    payload = request.args.get("payload")

    if not isinstance(payload, str):
        return "Invalid input", 400

    try:
        data: Dict = json.loads(payload)

        if "name" not in data:
            return "Invalid input", 400
    except ValueError as e:
        return f"Error processing payload: {str(e)}", 500

    return str(data.get("name"))


if __name__ == "__main__":
    app.run(debug=False) # Disable debug mode to avoid exposing Werkzeug debugger and allowing arbitrary code execution
</Code>
<Reason>
The implementation uses `literal_eval` which is insecure for deserializing user input. Replaced with secure JSON parsing using `json.loads`. Also, used type hinting to ensure the expected data structure is enforced.

